15	    pub start_line: usize,
16	    pub end_line: usize,
17	    pub nodes: usize,
18	}
19	
20	#[derive(Debug, Clone, Serialize)]
21	pub struct DuplicatePair {
22	    pub score: f64,
23	    pub left: PairEndpoint,
24	    pub right: PairEndpoint,
25	}
26	
27	pub struct Config {
28	    pub threshold: f64,
29	    pub min_lines: usize,
30	    pub min_nodes: usize,
31	    pub format: OutputFormat,
32	    pub excludes: Vec<String>,
33	}
34	
35	impl Default for Config {
36	    fn default() -> Self {
37	        Config {
38	            threshold: 0.82,
39	            min_lines: 4,
40	            min_nodes: 20,
41	            format: OutputFormat::Text,
42	            excludes: vec![],
43	        }
44	    }
45	}
46	
47	pub enum OutputFormat {
48	    Text,
49	    Json,
50	}
51	
52	pub enum RunResult {
53	    Clean,
54	    Duplicates(Vec<DuplicatePair>),
55	    Error(String),
56	}
57	
58	pub fn parse_output_format(s: &str) -> Result<OutputFormat, String> {
59	    match s {
60	        "json" => Ok(OutputFormat::Json),
61	        "text" => Ok(OutputFormat::Text),
62	        other => Err(format!("unknown format '{}'; use 'text' or 'json'", other)),
63	    }
64	}
65	
66	pub fn validate_lang(lang: &str) -> Result<(), String> {
67	    if lang == "rust" {
68	        Ok(())
69	    } else {
70	        Err(format!(
71	            "unsupported language '{}'; only 'rust' is supported",
72	            lang
73	        ))
74	    }
75	}
76	
77	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
78	    if a.is_empty() && b.is_empty() {
79	        return 1.0;
80	    }
81	    let set_a: HashSet<u64> = a.iter().copied().collect();
82	    let set_b: HashSet<u64> = b.iter().copied().collect();
83	    let intersection = set_a.intersection(&set_b).count();
84	    let union = set_a.union(&set_b).count();
85	    if union == 0 {
86	        return 0.0;
87	    }
88	    intersection as f64 / union as f64
89	}
90	
91	pub fn source_lines(fi: &FunctionInfo) -> usize {
92	    fi.end_line.saturating_sub(fi.start_line) + 1
93	}
94	
95	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
96	    let (left, right) = order_endpoints(a, b);
97	    DuplicatePair {
98	        score,
99	        left: PairEndpoint {
100	            file: left.file.clone(),
101	            start_line: left.start_line,
102	            end_line: left.end_line,
103	            nodes: left.node_hashes.len(),
104	        },
105	        right: PairEndpoint {
106	            file: right.file.clone(),
107	            start_line: right.start_line,
108	            end_line: right.end_line,
109	            nodes: right.node_hashes.len(),
110	        },
111	    }
112	}
113	
114	pub fn is_same_location(a: &FunctionInfo, b: &FunctionInfo) -> bool {
115	    a.file == b.file && a.start_line == b.start_line
116	}
117	
118	pub fn find_duplicate_pairs(
119	    functions: &[FunctionInfo],
120	    threshold: f64,
121	    min_lines: usize,
122	    min_nodes: usize,
123	) -> Vec<DuplicatePair> {
124	    let candidates: Vec<&FunctionInfo> = functions
125	        .iter()
126	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
127	        .collect();
128	
129	    let mut pairs: Vec<DuplicatePair> = Vec::new();
130	
131	    for i in 0..candidates.len() {
132	        for j in (i + 1)..candidates.len() {
133	            let a = candidates[i];
134	            let b = candidates[j];
135	            if is_same_location(a, b) {
136	                continue;
137	            }
138	            let score = jaccard(&a.node_hashes, &b.node_hashes);
139	            if score >= threshold {
140	                pairs.push(make_pair(a, b, score));
141	            }
142	        }
143	    }
144	
145	    pairs.sort_by(|a, b| {
146	        b.score
147	            .partial_cmp(&a.score)
148	            .unwrap_or(std::cmp::Ordering::Equal)
149	            .then_with(|| a.left.file.cmp(&b.left.file))
150	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
151	            .then_with(|| a.right.file.cmp(&b.right.file))
152	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
153	    });
154	
155	    pairs
156	}
157	
158	fn order_endpoints<'a>(
159	    a: &'a FunctionInfo,
160	    b: &'a FunctionInfo,
161	) -> (&'a FunctionInfo, &'a FunctionInfo) {
162	    let cmp = a
163	        .file
164	        .cmp(&b.file)
165	        .then_with(|| a.start_line.cmp(&b.start_line));
166	    if cmp == std::cmp::Ordering::Greater {
167	        (b, a)
168	    } else {
169	        (a, b)
170	    }
171	}
172	
173	pub fn format_text(pairs: &[DuplicatePair]) -> String {
174	    let mut out = String::new();
175	    for p in pairs {
176	        out.push_str(&format!("DUPLICATE score={:.4}\n", p.score));
177	        out.push_str(&format!(
178	            "  {}:{}-{}\n",
179	            p.left.file, p.left.start_line, p.left.end_line
180	        ));
181	        out.push_str(&format!(
182	            "  {}:{}-{}  ({} nodes / {} nodes)\n",
183	            p.right.file, p.right.start_line, p.right.end_line, p.left.nodes, p.right.nodes
184	        ));
185	    }
186	    out
187	}
188	
189	pub fn format_json(pairs: &[DuplicatePair]) -> String {
190	    serde_json::to_string_pretty(pairs).unwrap_or_else(|_| "[]".to_string())
191	}
192	
193	pub struct CliResult {
194	    pub exit_code: i32,
195	    pub stdout: String,
196	    pub stderr: String,
197	}
198	
199	fn cli_error(msg: String) -> CliResult {
200	    CliResult {
201	        exit_code: 2,
202	        stdout: String::new(),
203	        stderr: format!("error: {}", msg),
204	    }
205	}
206	
207	fn format_run_output(format: &OutputFormat, pairs: Vec<DuplicatePair>) -> String {
208	    match format {
209	        OutputFormat::Text => format_text(&pairs),
210	        OutputFormat::Json => format_json(&pairs),
211	    }
212	}
213	
214	fn clean_output(format: &OutputFormat) -> String {
215	    if matches!(format, OutputFormat::Json) {
216	        "[]".to_string()
217	    } else {
218	        String::new()
219	    }
220	}
221	
222	fn run_result_to_cli(result: RunResult, format: &OutputFormat) -> CliResult {
223	    match result {
224	        RunResult::Clean => CliResult {
225	            exit_code: 0,
226	            stdout: clean_output(format),
227	            stderr: String::new(),
228	        },
229	        RunResult::Duplicates(pairs) => CliResult {
230	            exit_code: 1,
231	            stdout: format_run_output(format, pairs),
232	            stderr: String::new(),
233	        },
234	        RunResult::Error(msg) => cli_error(msg),
235	    }
236	}
237	
238	pub fn execute_cli(
239	    paths: &[String],
240	    format_str: &str,
241	    lang: Option<&str>,
242	    config: Config,
243	    run_fn: impl Fn(&[String], &Config) -> RunResult,
244	) -> CliResult {
245	    let format = match parse_output_format(format_str) {
246	        Ok(f) => f,
247	        Err(e) => return cli_error(e),
248	    };
249	
250	    if let Some(lang) = lang
251	        && let Err(e) = validate_lang(lang)
252	    {
253	        return cli_error(e);
254	    }
255	
256	    let config = Config { format, ..config };
257	    let result = run_fn(paths, &config);
258	    run_result_to_cli(result, &config.format)
259	}
